// Costruisce il testo di notifica Markdown-safe.
const err = $input.first().json;

const workflow = err.workflow || {};
const execution = err.execution || {};
const lastNode = err.execution && err.execution.lastNodeExecuted ? err.execution.lastNodeExecuted : '?';

// Errore: sui trigger node arriva come stringa, sugli altri come oggetto.
const errorMessage = (() => {
  if (typeof err.error === 'string') return err.error;
  if (err.execution && err.execution.error) {
    const e = err.execution.error;
    return e.message || e.description || JSON.stringify(e).slice(0, 500);
  }
  return 'errore sconosciuto';
})();

const stamp = new Date().toLocaleString('it-IT', { timeZone: 'Europe/Rome' });

// Markdown V2 di Telegram richiede escape — uso plain text per semplicita'.
const text =
  '🚨 Alien Mind — errore workflow\n\n' +
  'Workflow: ' + (workflow.name || workflow.id || '?') + '\n' +
  'Nodo:     ' + lastNode + '\n' +
  'Quando:   ' + stamp + '\n\n' +
  'Errore:\n' + errorMessage.slice(0, 1500);

return [{ json: { text } }];
